+export const validateRequiredIfProps = (schema: ObjectSchema, path?: string): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    const requirements = attribute.props.requiredIf ?? []
+
+    if (requirements.length > 0 && attribute.props.key) {
+      throw new DynamoDBToolboxError('schema.requiredIf.keyAttribute', {
+        message: `Invalid conditional requirement${path !== undefined ? ` at path '${path}'` : ''}: Key attribute '${attributeName}' cannot be conditionally required.`,
