+      if (!(requirement.attributeName in schema.attributes)) {
+        throw new DynamoDBToolboxError('schema.requiredIf.invalidAttribute', {
+          message: `Invalid conditional requirement${path !== undefined ? ` at path '${path}'` : ''}: Controlling attribute '${requirement.attributeName}' must be a sibling.`,
