+export const validateRequiredIf = (schema: ObjectSchema, value: Record<string, unknown>, path: string[] = []): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.required === 'always' || value[attributeName] !== undefined) continue
+
+    const required = attribute.props.requiredIf?.some(({ attributeName: controller, values }) =>
+      value[controller] !== undefined && values.some(trigger => trigger === value[controller])
+    )
+    if (required) {
+      const valuePath = [...path, attributeName]
+      const formattedPath = formatArrayPath(valuePath)
+      throw new DynamoDBToolboxError('parsing.attributeRequired', {
+        message: `Attribute '${formattedPath}' is required.`,
+        path: formattedPath,
+        payload: {}
+      })
+    }
+  }
+}
