+export const requiredIfPaths = (
+  schema: ObjectSchema,
+  value: Record<string, unknown>,
+  path: string[] = []
+): string[][] => {
+  const paths: string[][] = []
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (value[attributeName] === undefined) continue
+    const nextPath = [...path, attribute.props.savedAs ?? attributeName]
+    if (attribute.type === 'map' && typeof value[attributeName] === 'object' && value[attributeName] !== null) {
+      paths.push(...requiredIfPaths(attribute, value[attributeName] as Record<string, unknown>, nextPath))
+    }
+  }
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (value[attributeName] !== undefined) continue
+    if (attribute.props.requiredIf?.some(({ attributeName: controller, values }) =>
+      value[controller] !== undefined && values.some(trigger => trigger === value[controller])
+    )) {
+      paths.push([...path, attribute.props.savedAs ?? attributeName])
+    }
+  }
+  return paths
+}
