  putLink,
  updateLink,
  transform,
  ...dto
}: AnySchemaDTO): AnySchema => {
  keyDefault
  putDefault
  updateDefault
  keyLink
  putLink
  updateLink
  transform

  let schema = any(dto)

  if (transform !== undefined) {
    const transformer = fromAnySchemaTransformerDTO(transform)

    if (transformer !== null) {
